#include <iostream>
#include <string>

std::string xorEncrypt(const std::string& password, char key) {
    std::string encrypted = password;
    for (size_t i = 0; i < encrypted.length(); ++i) {
        encrypted[i] ^= key;
    }
    return encrypted;
}

